Examples
--------
from mavenagi.commons import (
    AppUserIdentifier,
    AppUserRequest,
    EntityIdBase,
    UserData,
)

AppUserRequest(
    user_id=EntityIdBase(
        reference_id="user-0",
    ),
    identifiers=[
        AppUserIdentifier(
            value="joe@myapp.com",
            type="EMAIL",
        )
    ],
    data={
        "name": UserData(
            value="Joe",
            visibility="VISIBLE",
        )
    },
)
